```python
import requests

# Masukkan API Key Repliz kamu di sini
REPLIZ_API_KEY = "iAv4QhU3G2wXHeHzjHB3xf84pxhufPqU"
BASE_URL = "[https://api.repliz.com/v1](https://api.repliz.com/v1)"

def send_tiktok_dm(user_id: str, message: str):
    """
    Mengirim pesan DM otomatis ke user TikTok. 
    Gunakan ini untuk follow-up leads yang bertanya tentang kursus.
    """
    url = f"{BASE_URL}/chat/send"
    payload = {"user_id": user_id, "message": message}
    headers = {"Authorization": f"Bearer {REPLIZ_API_KEY}"}
    return requests.post(url, json=payload, headers=headers).json()

def reply_tiktok_comment(comment_id: str, text: str):
    """
    Membalas komentar di postingan TikTok. 
    Gunakan untuk menjawab pertanyaan publik secara cepat.
    """
    url = f"{BASE_URL}/comments/reply"
    payload = {"comment_id": comment_id, "text": text}
    headers = {"Authorization": f"Bearer {REPLIZ_API_KEY}"}
    return requests.post(url, json=payload, headers=headers).json()

def like_tiktok_comment(comment_id: str):
    """
    Memberikan Like pada komentar TikTok. 
    Gunakan sebagai bentuk apresiasi awal.
    """
    url = f"{BASE_URL}/comments/like"
    payload = {"comment_id": comment_id}
    headers = {"Authorization": f"Bearer {REPLIZ_API_KEY}"}
    return requests.post(url, json=payload, headers=headers).json()

