        if len(resp.text) < 5000:
            print(resp.text)
        else:
            # Just find API routes
            import re
            for m in re.finditer(r'[\"\\']/[^\"\\']{1,100}[\"\\']', resp.text):
                path = m.group()
                if any(kw in path.lower() for kw in ['like', 'reply', 'dm', 'chat', 'send', 'comment', 'message', 'tiktok']):
                    print(f'  Route: {path}')
    except Exception as e:
        print(f'\\n=== {url} === Error: {e}')
