(function() {
  // Check for Firebase auth state - Firebase stores in IndexedDB, not localStorage
  // Let's look at the window object for Firebase references
  const keys = [];
  for (let key in window) {
    if (key.toLowerCase().includes('firebase') || key.toLowerCase().includes('auth')) {
      keys.push(key);
    }
  }

  // Also check indexedDB databases
  return JSON.stringify({
    windowKeys: keys,
    localStorage: Object.keys(localStorage),
    cookie: document.cookie
  }, null, 2);
})()

