(function() {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('firebaseLocalStorageDb', 1);
    request.onsuccess = function(event) {
      const db = event.target.result;
      try {
        const transaction = db.transaction('firebaseLocalStorage', 'readonly');
        const store = transaction.objectStore('firebaseLocalStorage');
        const getAll = store.getAll();
        getAll.onsuccess = function() {
          const result = getAll.result;
          // Try to get the session token
          let sessionToken = null;
          let userData = null;
          for (const item of result) {
            if (item.fbase_key && item.fbase_key.includes('session')) {
              sessionToken = item;
            }
            userData = item;
          }
          resolve(JSON.stringify({
            count: result.length,
            data: result.map(r => ({
              key: Object.keys(r).filter(k => k !== 'value'),
              hasValue: !!r.value,
              valueType: typeof r.value,
              valueKeys: r.value ? Object.keys(r.value) : null
            }))
          }, null, 2));
        };
        getAll.onerror = function() {
          reject('Error getting data');
        };
      } catch(e) {
        reject(e.message);
      }
    };
    request.onerror = function() {
      reject('Error opening DB');
    };
    // Handle upgrade needed (DB might not exist)
    request.onupgradeneeded = function(event) {
      resolve('DB needs upgrade: ' + event.type);
    };
  });
})()

