(function() {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('firebaseLocalStorageDb', 1);
    request.onsuccess = function(event) {
      const db = event.target.result;
      try {
        // Check if object store exists
        if (!db.objectStoreNames.contains('firebaseLocalStorage')) {
          resolve('No firebaseLocalStorage store found. Stores: ' + JSON.stringify([...db.objectStoreNames]));
          return;
        }
        const transaction = db.transaction('firebaseLocalStorage', 'readonly');
        const store = transaction.objectStore('firebaseLocalStorage');
        const getAll = store.getAll();
        getAll.onsuccess = function() {
          const result = getAll.result;
          resolve(JSON.stringify(result, null, 2));
        };
        getAll.onerror = function() {
          reject('Error getting data: ' + getAll.error);
        };
      } catch(e) {
        reject('Error: ' + e.message);
      }
    };
    request.onupgradeneeded = function(event) {
      const db = event.target.result;
      // Create the store if it doesn't exist
      if (!db.objectStoreNames.contains('firebaseLocalStorage')) {
        db.createObjectStore('firebaseLocalStorage');
      }
      resolve('upgraded');
    };
    request.onerror = function() {
      reject('Error opening DB: ' + request.error);
    };
  });
})()

