(function() {
  // Let's find the current auth token by patching the axios request interceptor
  // Or better, let's just look at the internal state
  // The browser uses Firebase Auth - let's try to get the current user token

  return new Promise((resolve) => {
    // Check if Firebase Auth is available through the window
    try {
      // Firebase Auth SDK stores the user in IndexedDB
      const openReq = indexedDB.open('firebaseLocalStorageDb', 1);
      openReq.onupgradeneeded = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains('firebaseLocalStorage')) {
          db.createObjectStore('firebaseLocalStorage');
        }
        resolve('upgraded');
      };
      openReq.onsuccess = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains('firebaseLocalStorage')) {
          // Try without specific store
          resolve('No firebaseLocalStorage store');
          return;
        }
        const tx = db.transaction('firebaseLocalStorage', 'readonly');
        const store = tx.objectStore('firebaseLocalStorage');
        const getAll = store.getAll();
        getAll.onsuccess = () => {
          const items = getAll.result;
          if (items && items.length > 0) {
            resolve(JSON.stringify(items.map(i => ({
              key: Object.keys(i).filter(k => k !== 'value'),
              valueType: typeof i.value,
              hasStsTokenManager: i.value && i.value.stsTokenManager ? true : false,
              hasAccessToken: i.value && i.value.stsTokenManager && i.value.stsTokenManager.accessToken ? true : false
            }))));
          } else {
            resolve('No items in firebaseLocalStorage');
          }
        };
        getAll.onerror = () => resolve('Error getting items');
      };
      openReq.onerror = () => resolve('Error opening DB');
    } catch(e) {
      resolve('Error: ' + e.message);
    }
  });
})()

