(function() {
  // Let's look at the Firebase auth state differently
  // Check all IndexedDB databases and their stores
  return new Promise((resolve) => {
    indexedDB.databases().then(dbs => {
      const results = {};
      let completed = 0;

      if (dbs.length === 0) {
        resolve('No databases found');
        return;
      }

      for (const dbInfo of dbs) {
        const req = indexedDB.open(dbInfo.name, dbInfo.version);
        req.onsuccess = (e) => {
          const db = e.target.result;
          const stores = [...db.objectStoreNames];
          results[dbInfo.name] = stores;
          completed++;
          if (completed === dbs.length) {
            resolve(JSON.stringify(results, null, 2));
          }
        };
        req.onerror = (e) => {
          results[dbInfo.name] = 'Error: ' + e.target.error;
          completed++;
          if (completed === dbs.length) {
            resolve(JSON.stringify(results, null, 2));
          }
        };
      }
    }).catch(e => {
      resolve('Error getting databases: ' + e.message);
    });
  });
})()

