(function() {
  // Check if there's a like endpoint for comments
  // Try various like endpoints
  const endpoints = [
    { method: 'post', url: '/comment/6a06dfe6cbf965200ba1398a/like' },
    { method: 'post', url: '/comment/like', data: { commentId: '6a06dfe6cbf965200ba1398a' } },
    { method: 'put', url: '/comment/6a06dfe6cbf965200ba1398a', data: { action: 'like' } },
  ];

  async function test() {
    for (const ep of endpoints) {
      try {
        let resp;
        if (ep.method === 'post') {
          resp = await document.axios.post(ep.url, ep.data || {});
        } else if (ep.method === 'put') {
          resp = await document.axios.put(ep.url, ep.data || {});
        }
        console.log(`${ep.method.toUpperCase()} ${ep.url}: ${resp.status} - ${JSON.stringify(resp.data).substring(0, 200)}`);
      } catch(e) {
        const status = e.response ? e.response.status : 'err';
        console.log(`${ep.method.toUpperCase()} ${ep.url}: ${status}`);
      }
    }
    return 'Done testing like endpoints';
  }

  return test();
})()

