  async function handleComments() {
    const replies = [
      { id: '6a06e399cbf965200ba1a642', text: 'Halo kak! Terima kasih minatnya. Untuk info harga kursus, silakan cek DM ya kak, akan kami kirimkan detailnya. 😊' },
