    ];

    const results = [];
    for (const r of replies) {
      try {
        const resp = await document.axios.post('/comment/' + r.id, { text: r.text });
        results.push({ id: r.id, status: 'SUCCESS', data: resp.data });
      } catch(e) {
        const status = e.response ? e.response.status : 'error';
        const data = e.response ? JSON.stringify(e.response.data).substring(0, 100) : e.message;
        results.push({ id: r.id, status: 'ERROR (' + status + ')', data: data });
      }
    }
    return JSON.stringify(results, null, 2);
  }
  return handleComments();
})()

