from fastapi import FastAPI, Request
import requests
import json

app = FastAPI()

# KONFIGURASI SESUAI ID AGENT KAMU
QWENPAW_CHAT_URL = "http://127.0.0.1:8088/api/console/chat"
AGENT_ID = "PhAtXm" 

@app.post("/webhook-repliz")
async def bridge_to_qwen(request: Request):
    try:
        raw_data = await request.json()

        # Ambil data dasar saja
        comment_obj = raw_data.get("comment", {})
        komentar = comment_obj.get("text") or "Ada interaksi baru"
        username = comment_obj.get("owner", {}).get("name") or "User"

        print(f"📩 Masuk: @{username} bilang '{komentar}'")

        # Instruksi simpel karena Navi sudah akses Repliz langsung
        payload = {
            "input": [
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "text",
                            "text": f"User @{username} baru saja komentar di TikTok: '{komentar}'. Navi, tolong berikan respon yang sesuai."
                        }
                    ]
                }
            ],
            "session_id": f"tiktok-{username}",
            "user_id": "repliz-bridge",
            "channel": "console"
        }

        headers = {
            "Content-Type": "application/json",
            "X-Agent-Id": AGENT_ID
        }

        print(f"🔄 Meneruskan ke Navi ({AGENT_ID})...")
        response = requests.post(QWENPAW_CHAT_URL, json=payload, headers=headers, timeout=10)

        if response.status_code == 200:
            print(f"✅ BERHASIL! Navi sudah menerima laporan.")
            return {"status": "success"}
        else:
            print(f"❌ Gagal: {response.status_code}")
            return {"status": "failed"}

    except Exception as e:
        print(f"💥 Error: {str(e)}")
        return {"status": "error"}

