(function() {
  // Check if there's a "Message" or "DM" button on the page
  const allElements = document.querySelectorAll('button, a, [role="button"]');
  const results = [];
  allElements.forEach(el => {
    const text = el.textContent?.trim();
    if (text && (text.toLowerCase().includes('message') || text.toLowerCase().includes('dm') || text.toLowerCase().includes('chat') || text.toLowerCase().includes('kirim'))) {
      results.push({ text: text, tag: el.tagName, class: el.className?.substring(0, 50) });
    }
  });

  if (results.length === 0) {
    // Check all button texts
    const btns = document.querySelectorAll('button');
    btns.forEach(b => {
      if (b.textContent?.trim()) {
        results.push({ text: b.textContent.trim().substring(0, 30), visible: b.offsetParent !== null });
      }
    });
  }

  return JSON.stringify(results, null, 2);
})()

